select apply_id, apply_no, user_id, channel_id, channel_type, apply_name, materials_json,
       apply_status, audit_remark, submit_time, audit_time
from jst_channel_auth_apply

    del_flag = '0'

        and apply_no = #{applyNo}


        and apply_name like concat('%', #{applyName}, '%')


        and user_id = #{userId}


        and apply_status = #{applyStatus}


        and channel_type = #{channelType}


order by submit_time desc, apply_id desc

